/* rtos_timer.h - RTOS Software Timer API */
#ifndef RTOS_TIMER_H
#define RTOS_TIMER_H

#include <stdint.h>

typedef void *timer_handle_t;
typedef void (*timer_callback_t)(timer_handle_t handle, void *arg);

/**
 * @brief Create a software timer
 * @param name      Timer name string
 * @param period_ms Period in milliseconds
 * @param repeat    Non-zero for repeating timer
 * @param cb        Callback function
 * @param arg       User argument passed to callback
 * @return Timer handle, or NULL on failure
 */
timer_handle_t timer_create(const char *name,
                            uint32_t    period_ms,
                            uint8_t     repeat,
                            timer_callback_t cb,
                            void       *arg);

void timer_start(timer_handle_t handle);
void timer_stop(timer_handle_t handle);
void timer_delete(timer_handle_t handle);

/* timer_get_remaining_ms() removed; use timer_get_status() instead */
typedef struct {
    uint32_t remaining_ms;
    uint8_t  is_running;
} timer_status_t;
void timer_get_status(timer_handle_t handle, timer_status_t *status);

#endif /* RTOS_TIMER_H */

